int kthSmallest(struct TreeNode* root, int k) {
    struct TreeNode* stack[1000];
    int top = 0;
    struct TreeNode* cur = root;
    while (cur || top) {
        while (cur) { stack[top++] = cur; cur = cur->left; }
        cur = stack[--top];
        if (--k == 0) return cur->val;
        cur = cur->right;
    }
    return -1;
}
